import { useNodesState, useEdgesState } from "reactflow";
import { PipelineToolbar } from "./toolbar";
import { PipelineUI } from "./ui";
import FlowCanvas from "./FlowCanvas";

function App() {
  const [nodes, setNodes, onNodesChange] = useNodesState([
    { id: "1", type: "inputNode", position: { x: 50, y: 50 }, data: {} },
    { id: "2", type: "llmNode", position: { x: 300, y: 50 }, data: {} },
    { id: "3", type: "textNode", position: { x: 50, y: 200 }, data: {} },
    { id: "4", type: "outputNode", position: { x: 300, y: 200 }, data: {} },
    {
      id: "5",
      type: "deleteNode",
      position: { x: 550, y: 125 },
      data: { incoming: null, onDelete: () => {} }, // will inject on mount
    },
  ]);

  const [edges, setEdges, onEdgesChange] = useEdgesState([
    { id: "e1-2", source: "1", target: "2" },
    { id: "e3-2", source: "3", target: "2" },
    { id: "e2-4", source: "2", target: "4" },
  ]);

  // 🔥 Delete target node and also remove DeleteNode itself
  const handleDeleteNode = (targetId) => {
    setNodes((nds) =>
      nds.filter((n) => n.id !== targetId && n.type !== "deleteNode")
    );
    setEdges((eds) =>
      eds.filter(
        (e) =>
          e.source !== targetId &&
          e.target !== targetId &&
          e.source !== "5" &&
          e.target !== "5"
      )
    );
  };

  // 🔁 Update DeleteNode's incoming dynamically based on latest edges
  const handleEdgesChange = (changes) => {
    const updatedEdges = onEdgesChange(changes);

    const incomingMap = updatedEdges.reduce((acc, edge) => {
      if (edge.target === "5") {
        acc["5"] = edge.source;
      }
      return acc;
    }, {});

    setNodes((nds) =>
      nds.map((n) =>
        n.id === "5"
          ? {
              ...n,
              data: {
                ...n.data,
                incoming: incomingMap["5"] || null,
                onDelete: handleDeleteNode,
              },
            }
          : n
      )
    );

    setEdges(updatedEdges);
  };

  return (
    <div>
      <PipelineToolbar />
      <PipelineUI />
      <FlowCanvas
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={handleEdgesChange}
        onConnect={(params) => setEdges((eds) => [...eds, params])}
      />
    </div>
  );
}

export default App;
